  return <Toggle label="Disable AI" />;
}

// aria-live wraps AI output (React)
export function AiAnswer({ content }: { content: string }) {
  return (
    <div aria-live="polite">
      <AILabel>AI</AILabel>
      <p>{content}</p>
    </div>
  );
}

